  try {
    var session = LockService.getScriptLock();
    session.waitLock(30000); // تجنب تداخل البيانات عند الطلب المتزامن
    
    var jsonString = e.postData.contents;
    var data = JSON.parse(jsonString);
    
    var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
    
    // إذا كان الجدول فارغاً، نقوم بإنشاء الهيدر
    if (sheet.getLastRow() === 0) {
      sheet.appendRow([
        "رقم الطلب", "تاريخ الطلب", "اسم الزبون", "رقم الهاتف", 
        "الولاية", "البلدية", "العنوان الكامل", "نوع التوصيل", 
        "المنتجات وتفاصيلها", "سعر السلع", "سعر التوصيل التطبيقي", 
        "الخصم الممنوح", "المجموع الكلي للطلب", "تكلفة الشراء الفعلية", 
        "تكلفة الشحن الحقيقية", "صافي الربح الفعلي", "حالة الطلبية"
      ]);
    }
    
    // البحث عن طلب موجود مسبقاً لتحديثه، أو إنشاء سطر جديد
    var orderId = data.orderId;
    var lastRow = sheet.getLastRow();
    var foundRow = -1;
    
    if (lastRow > 1) {
      var range = sheet.getRange(2, 1, lastRow - 1, 1);
      var values = range.getValues();
      for (var i = 0; i < values.length; i++) {
        if (values[i][0] == orderId) {
          foundRow = i + 2; // +2 لأن الفهرس يبدأ من 2
          break;
        }
      }
    }
    
    var rowData = [
      data.orderId,
      data.createdAt || new Date().toLocaleString(),
      data.customerName,
      "'" + data.phone, // إضافة علامة الاقتباس لمنع جوجل من إزالة الصفر الأول
      data.wilaya,
      data.commune,
      data.address,
      data.deliveryType === 'desk' ? "المكتب" : "المنزل",
      data.itemsDetail,
      data.subtotal,
      data.appliedDeliveryPrice,
      data.discount,
      data.total,
      data.purchaseCost,
      data.realDeliveryPrice,
      data.netProfit,
      data.status
    ];
    
    if (foundRow !== -1) {
      // تحديث الطلب الموجود
      sheet.getRange(foundRow, 1, 1, rowData.length).setValues([rowData]);
    } else {
      // إضافة سطر جديد
      sheet.appendRow(rowData);
    }
    
    session.releaseLock();
    return ContentService.createTextOutput(JSON.stringify({ "status": "success", "row": foundRow !== -1 ? foundRow : sheet.getLastRow() }))
                         .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    if (session) session.releaseLock();
    return ContentService.createTextOutput(JSON.stringify({ "status": "error", "message": error.toString() }))
                         .setMimeType(ContentService.MimeType.JSON);
  }
